import numpy as np

def bag_of_words(corpus: list[str]) -> tuple[dict, np.ndarray]:
    # Build vocabulary
    all_words = set()
    tokenized = []
    for doc in corpus:
        tokens = doc.lower().split()
        tokenized.append(tokens)
        all_words.update(tokens)
    vocab = {word: idx for idx, word in enumerate(sorted(all_words))}
    # Build matrix
    matrix = np.zeros((len(corpus), len(vocab)), dtype=int)
    for i, tokens in enumerate(tokenized):
        for token in tokens:
            if token in vocab:
                matrix[i, vocab[token]] += 1
    return vocab, matrix
